import React from "react";
import ServiceDashboard from "../components/service/ServiceDashboard";

export default function ServicePortal() {
  return (
    <div className="page">
      <h1>Service Provider Portal</h1>
      <p className="muted">
        Example of how any dApp can plug into the reusable KYC credential and
        gate access by level.
      </p>
      <div className="grid">
        <ServiceDashboard />
      </div>
    </div>
  );
}
